{
  "query": "OpenAI Deep Research 2025-2026 product details, capabilities, benchmarks, comparisons, and technical reports",
  "candidate_urls": [
    {
      "url": "https://openai.com/index/introducing-deep-research/",
      "reason": "Official OpenAI launch blog post with all product details, updates, benchmarks, and limitations."
    },
    {
      "url": "https://cdn.openai.com/deep-research-system-card.pdf",
      "reason": "Official system card with safety evaluations and technical details about the model."
    },
    {
      "url": "https://help.openai.com/en/articles/10500283-deep-research?pubDate=20250425",
      "reason": "Official help center article with usage instructions, plan limits, and capabilities."
    },
    {
      "url": "https://developers.openai.com/api/docs/guides/deep-research",
      "reason": "API documentation for deep research models with technical integration details."
    },
    {
      "url": "https://www.axios.com/2025/02/02/chatgpt-deep-research-openai-agents",
      "reason": "News article from Axios covering the launch and early analysis."
    },
    {
      "url": "https://economictimes.indiatimes.com/tech/artificial-intelligence/et-explainer-all-you-wanted-to-know-about-open-ais-deep-research/articleshow/117980156.cms",
      "reason": "Explainer article from Economic Times covering launch context and comparison with Operator."
    },
    {
      "url": "https://aimagazine.com/ai-applications/deep-research-inside-openais-new-analysis-tool",
      "reason": "AI Magazine article with details on training methodology and capabilities."
    },
    {
      "url": "https://arxiv.org/abs/2506.18096",
      "reason": "Survey paper on Deep Research agents, comparing OpenAI DR with other systems."
    },
    {
      "url": "https://arxiv.org/pdf/2601.08536",
      "reason": "DeepResearch Bench II paper benchmarking OpenAI DR against other agents."
    },
    {
      "url": "https://arxiv.org/pdf/2510.15862",
      "reason": "Paper on RL-based deep research agents, comparing design choices."
    }
  ],
  "fetched_sources": [
    {
      "title": "Introducing deep research (OpenAI official blog, Punjabi version)",
      "url": "https://openai.com/pa-IN/index/introducing-deep-research/",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Launched February 2, 2025. Powered by a version of OpenAI o3 optimized for web browsing and data analysis. Trained with end-to-end RL on browsing and reasoning tasks. Takes 5-30 minutes per task. Produces cited comprehensive reports. Available to Pro users initially (100 queries/month), later expanded. Benchmarks: Humanity's Last Exam 26.6% accuracy (previous SOTA o3-mini high 13.0%); GAIA SOTA with 67.36% pass@1 and 72.57% cons@64. Updates: Feb 5 2025 (UK/EEA Pro), Feb 25 (All Plus), Apr 24 2025 (Plus/Team/Enterprise/Edu: 25/mo, Pro: 250/mo, Free: 5/mo; lightweight version powered by o4-mini), Jul 17 2025 (visual browser in agent mode), Feb 10 2026 (MCP connectivity, trusted site restriction, real-time progress tracking). Limitations: can hallucinate, struggles with rumors, confidence calibration issues.",
      "notes": "Official OpenAI blog content retrieved via alternative URL. Main blog at openai.com/index/introducing-deep-research/ returned 403."
    },
    {
      "title": "Deep Research System Card",
      "url": "https://cdn.openai.com/deep-research-system-card.pdf",
      "fetch_status": "partial",
      "reliability": "high",
      "evidence": "PDF system card dated February 25, 2025. Describes safety testing, Preparedness Framework evaluations. Model classified as Medium risk. Trained on browsing datasets created for research use cases. Evaluated for cybersecurity, CBRN, persuasion, model autonomy risks. SWE-Bench Verified shows competent coding task execution. Performance on real-world ML research evaluations still limited. Includes pre-mitigation and post-mitigation model evaluations. Safety measures include privacy protections and malicious instruction resistance.",
      "notes": "PDF could not be fully extracted as text, but key details obtained from search snippets and deployment safety page."
    },
    {
      "title": "Deep research in ChatGPT (Help Center)",
      "url": "https://help.openai.com/en/articles/10500283-deep-research?pubDate=20250425",
      "fetch_status": "failed",
      "reliability": "medium",
      "evidence": "Help article updated as of 2 days ago (relative to search). Describes deep research as multi-step research tool. Supports uploaded files, web search, specific site restriction, ChatGPT apps. Output includes citations, fullscreen report view. Downloadable formats: Markdown, Word, PDF. Powered by latest model by default, legacy models optional. Usage resets every 30 days.",
      "notes": "URL returned 403. Information derived from search snippets."
    },
    {
      "title": "Deep research API documentation",
      "url": "https://developers.openai.com/api/docs/guides/deep-research",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "API supports o3-deep-research and o4-mini-deep-research models. Requires at least one data source: web search, remote MCP servers, or file search with vector stores. Supports code interpreter tool. Background mode recommended for long tasks. max_tool_calls parameter to control cost/latency. Supports web search (search, open_page, find_in_page actions), file search (max 2 vector stores), remote MCP servers (search+fetch interface only), code interpreter. Does NOT support function calling. Prompt injection risks documented with CRM data exfiltration example. MCP require_approval must be 'never' for deep research. Safety mitigations: trusted MCP only, log review, phased calling, LLM monitor in loop.",
      "notes": "Fetched successfully. Detailed technical documentation."
    },
    {
      "title": "ET Explainer: All you wanted to know about OpenAI’s deep research",
      "url": "https://economictimes.indiatimes.com/tech/artificial-intelligence/et-explainer-all-you-wanted-to-know-about-open-ais-deep-research/articleshow/117980156.cms",
      "fetch_status": "success",
      "reliability": "medium",
      "evidence": "Published Feb 6, 2025. Deep research is OpenAI's second AI agent (after Operator). Uses o3 model. Trained with RL like o1. Sam Altman: 'very compute-intensive and slow, but the first AI system that can do such a wide variety of complex, valuable tasks.' Altman called it a 'superpower' with 'experts on demand'. Contrast with Operator: Operator handles repetitive browser tasks (forms, ordering groceries), deep research is for research purposes. DeepSeek context: DeepSeek built for under $6M vs GPT-4's reported $100M.",
      "notes": "News article, medium reliability due to being secondary source."
    },
    {
      "title": "Deep Research: Inside OpenAI's New Analysis Tool (AI Magazine)",
      "url": "https://aimagazine.com/ai-applications/deep-research-inside-openais-new-analysis-tool",
      "fetch_status": "success",
      "reliability": "medium",
      "evidence": "Published Feb 4, 2025. Describes deep research as 'new agentic capability'. 5-30 minutes per task. Trained with end-to-end RL. Uses o3 model. Vision for combining deep research (asynchronous online investigation) with Operator (real-world action) for increasingly sophisticated tasks. Every output cited. Can attach files and spreadsheets.",
      "notes": "Secondary source summarizing official launch."
    },
    {
      "title": "Deep Research Agents: A Systematic Examination And Roadmap (arXiv 2506.18096)",
      "url": "https://arxiv.org/abs/2506.18096",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Academic survey paper (Jun 2025, updated Sep 2025). Describes OpenAI DR as using single-agent architecture with RL-fine-tuned o3 model. Three significant advancements: (1) dynamically adaptive iterative research workflow, (2) enhanced context memory and multimodal processing, (3) comprehensive toolchain integration (web browsing + programming tools + precise citations). Compares with Gemini DR, Grok DeepSearch, Perplexity DR, and open-source agents. Identifies benchmark limitations and open challenges.",
      "notes": "Peer-reviewed academic paper, high reliability."
    },
    {
      "title": "DeepResearch Bench II: Diagnosing Deep Research Agents via Rubrics from Expert Report (arXiv 2601.08536)",
      "url": "https://arxiv.org/pdf/2601.08536",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Benchmarks deep research agents as of November 2025. OpenAI-GPT-o3 Deep Research emerges as strongest overall agent, highest in Information Recall and overall aggregated metric. But even best agent fails >50% of rubrics. Gemini-3-Pro and Gemini-2.5-Pro Deep Research competitive in Analysis. Grok Deep Search leads in Presentation but lags in retrieval/reasoning. Tongyi Deep Research ranks lowest. Clear gap between current DRAs and human experts.",
      "notes": "Preprint, peer-reviewed quality. Provides benchmark data for comparison."
    },
    {
      "title": "Rethinking the Design of Reinforcement Learning-Based Deep Research Agents (arXiv 2510.15862)",
      "url": "https://arxiv.org/pdf/2510.15862",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Academic paper studying design choices for RL-based deep research agents. Shows AI feedback as reward substantially outperforms F1 score. RLOO more sample-efficient than GRPO. Live web search during training improves performance. Error-tolerant test-time rollout further improves accuracy. Base agent uses Qwen2.5-7B-Instruct; achieves competitive performance among 7B agents. References OpenAI DR as the pioneering system that inspired the field.",
      "notes": "Preprint, strong methodology. Provides comparative analysis of training techniques."
    },
    {
      "title": "Deep Research System Card (Deployment Safety Hub)",
      "url": "https://deploymentsafety.openai.com/deep-research",
      "fetch_status": "success",
      "reliability": "high",
      "evidence": "Official safety documentation. Deep research classified as Medium risk under Preparedness Framework. Summary: improved performance on longer-horizon agentic tasks relevant to model autonomy. SWE-Bench Verified shows competent well-specified coding task execution. Poor performance on open-ended ML research evaluations for self-improvement. Includes human probing and automated testing for select risks. Safety Advisory Group involved. Mitigations include deliberative alignment.",
      "notes": "Official OpenAI safety page, high reliability."
    }
  ]
}
